232→/// Generate a complex-typed value with `__complex_type` tagged wire format.
233→///
234→/// Dispatches to per-kind generators. Each generator produces boundary-biased values.
235→fn generate_complex_value(
236→    kind: ComplexKind,
237→    metadata: &serde_json::Map<String, serde_json::Value>,
238→    _inner: Option<&TypeInfo>,
239→    rng: &mut impl Rng,
240→) -> Value {
241→    match kind {
242→        ComplexKind::Date | ComplexKind::DateTime => generate_date(rng),
243→        ComplexKind::Duration => generate_duration(rng),
244→        ComplexKind::Time => generate_time(rng),
245→        ComplexKind::RegExp => generate_regexp(rng),
246→        ComplexKind::Url => generate_url(rng),
247→        ComplexKind::Error => generate_error(metadata, rng),
248→        ComplexKind::BigInt => generate_bigint(rng),
249→        ComplexKind::BigDecimal => generate_big_decimal(rng),
250→        ComplexKind::Uuid => generate_uuid(rng),
251→        ComplexKind::IpAddress => generate_ip_address(rng),
252→        ComplexKind::Path => generate_path(rng),
253→        ComplexKind::Buffer => generate_buffer(rng),
254→        ComplexKind::Symbol => generate_symbol(rng),
255→        ComplexKind::Char | ComplexKind::Rune => generate_char(rng),
256→        ComplexKind::GoByte => generate_go_byte(rng),
257→        ComplexKind::Email => generate_email(rng),
258→        ComplexKind::SemVer => generate_semver(rng),
259→        ComplexKind::Color => generate_color(rng),
260→        ComplexKind::GeoPoint => generate_geo_point(rng),
261→        ComplexKind::Money => generate_money(rng),
262→        ComplexKind::MimeType => generate_mime_type(rng),
263→        ComplexKind::Locale => generate_locale(rng),
264→        ComplexKind::Range => generate_range(rng),
265→        ComplexKind::Complex => generate_complex_number(rng),
266→        ComplexKind::Rational => generate_rational(rng),
267→        ComplexKind::BitSet => generate_bitset(rng),
268→        ComplexKind::Option => generate_option(rng),
269→        ComplexKind::Result => generate_result(rng),
270→        ComplexKind::Closure => generate_closure(rng),
271→        ComplexKind::Iterator => generate_iterator(rng),
272→    }
273→}
