1395→/// Produce two children by crossing over two parent input vectors.
1396→///
1397→/// With probability `crossover_rate`, performs type-aware crossover; otherwise
1398→/// clones both parents unchanged. At the parameter level, uniform crossover
1399→/// randomly assigns each parameter from parent A or B. Object and array
1400→/// parameters use finer-grained strategies (field-level and single-point,
1401→/// respectively).
1402→pub fn crossover_inputs(
1403→    parent_a: &[Value],
1404→    parent_b: &[Value],
1405→    params: &[crate::types::ParamInfo],
1406→    crossover_rate: f64,
1407→    rng: &mut impl Rng,
1408→) -> (Vec<Value>, Vec<Value>) {
1409→    let len = parent_a.len().min(parent_b.len()).min(params.len());
1410→
1411→    // No crossover — clone parents
1412→    if rng.random_range(0.0..1.0_f64) >= crossover_rate {
1413→        return (parent_a.to_vec(), parent_b.to_vec());
1414→    }
1415→
1416→    let mut child1 = Vec::with_capacity(len);
1417→    let mut child2 = Vec::with_capacity(len);
1418→
1419→    for i in 0..len {
1420→        let (c1, c2) = crossover_value(&parent_a[i], &parent_b[i], &params[i].typ, rng);
1421→        child1.push(c1);
1422→        child2.push(c2);
1423→    }
1424→
1425→    (child1, child2)
1426→}
