1498→/// Single-point crossover for arrays: pick a crossover point, swap tails.
1499→fn crossover_array(a: &Value, b: &Value, rng: &mut impl Rng) -> (Value, Value) {
1500→    let arr_a = a.as_array();
1501→    let arr_b = b.as_array();
1502→
1503→    let (Some(arr_a), Some(arr_b)) = (arr_a, arr_b) else {
1504→        return if rng.random_bool(0.5) {
1505→            (a.clone(), b.clone())
1506→        } else {
