1901→fn literal_matches_type(lit: &LiteralValue, typ: &TypeInfo) -> Option<Value> {
1902→    match (lit, typ) {
1903→        (LiteralValue::Int { value }, TypeInfo::Int) => Some(json!(value)),
1904→        (LiteralValue::Int { value }, TypeInfo::Float) => Some(json!(*value as f64)),
1905→        (LiteralValue::Float { value }, TypeInfo::Float) => Some(json!(value)),
1906→        (LiteralValue::Str { value }, TypeInfo::Str) => Some(json!(value)),
1907→        (LiteralValue::Bool { value }, TypeInfo::Bool) => Some(json!(value)),
1908→        // For union types, try each variant
1909→        (_, TypeInfo::Union { variants }) => {
1910→            variants.iter().find_map(|v| literal_matches_type(lit, v))
1911→        }
1912→        // For nullable, try the inner type
1913→        (_, TypeInfo::Nullable { inner }) => literal_matches_type(lit, inner),
1914→        // Regex literal → Str param: try the pattern as a string input
1915→        (LiteralValue::Regex { pattern }, TypeInfo::Str) => Some(json!(pattern)),
1916→        _ => None,
1917→    }
1918→}
