// ---------------------------------------------------------------------------
// Mock value generation
// ---------------------------------------------------------------------------

use crate::auto_mock::{IoCategory, MockParam};
use crate::protocol::{MockBehavior, MockConfig};

/// Generate a [`MockConfig`] for each [`MockParam`], producing
/// `call_count_estimate` return values per mock.
///
/// For typed returns, delegates to [`generate_random_value`]. For `Unknown`
/// returns, falls back to category-aware shaping (e.g. `{rows: []}` for DB
/// queries, `{status: 200, data: {}}` for network calls).
///
/// Union types containing a `Complex { kind: Error, .. }` variant produce both
/// success and error return values so the explorer exercises error paths.
/// Similarly, `Complex { kind: Result, .. }` returns generate ok and err
/// variants.
pub fn generate_mock_values(
    params: &[MockParam],
    rng: &mut impl Rng,
    caps: Option<&FrontendCapabilities>,
) -> Vec<MockConfig> {
    params
        .iter()
        .map(|mp| {
            let count = (mp.call_count_estimate as usize).max(1);
            let return_values = generate_mock_return_values(mp, count, rng, caps);
            MockConfig {
                symbol: mp.symbol.clone(),
                return_values,
                should_track_calls: true,
                default_behavior: MockBehavior::RepeatLast,
            }
        })
        .collect()
}

/// Mutate mock return values in-place while preserving type contracts.
///
/// For each mock config, applies [`mutate_value`] to each return value
/// with the given `mutation_rate` probability.
pub fn mutate_mock_values(
    configs: &[MockConfig],
    params: &[MockParam],
    mutation_rate: f64,
    rng: &mut impl Rng,
) -> Vec<MockConfig> {
    configs
        .iter()
        .zip(params.iter())
        .map(|(cfg, mp)| {
            let return_values = cfg
                .return_values
                .iter()
                .map(|val| {
                    if rng.random_range(0.0..1.0_f64) < mutation_rate {
                        mutate_value(val, &mp.return_type, &[], rng)
                    } else {
                        val.clone()
                    }
                })
                .collect();
            MockConfig {
                symbol: cfg.symbol.clone(),
                return_values,
                should_track_calls: cfg.should_track_calls,
                default_behavior: cfg.default_behavior.clone(),
            }
        })
        .collect()
}

/// Cross over two sets of mock configs, preserving vector structure.
///
/// For each position, performs uniform crossover on corresponding return
/// value vectors. Both parents must have the same number of configs
/// (aligned with `params`); mismatches are handled by taking the minimum
/// length.
pub fn crossover_mock_values(
    parent_a: &[MockConfig],
    parent_b: &[MockConfig],
    params: &[MockParam],
    crossover_rate: f64,
    rng: &mut impl Rng,
) -> (Vec<MockConfig>, Vec<MockConfig>) {
    let len = parent_a.len().min(parent_b.len()).min(params.len());

    if rng.random_range(0.0..1.0_f64) >= crossover_rate {
        return (parent_a.to_vec(), parent_b.to_vec());
    }

    let mut child1 = Vec::with_capacity(len);
    let mut child2 = Vec::with_capacity(len);

    for i in 0..len {
        let a_vals = &parent_a[i].return_values;
        let b_vals = &parent_b[i].return_values;
        let val_len = a_vals.len().min(b_vals.len());
        let mp = &params[i];

        let mut c1_vals = Vec::with_capacity(val_len);
        let mut c2_vals = Vec::with_capacity(val_len);

        for j in 0..val_len {
            let (v1, v2) = crossover_value(&a_vals[j], &b_vals[j], &mp.return_type, rng);
            c1_vals.push(v1);
            c2_vals.push(v2);
        }

        child1.push(MockConfig {
            symbol: mp.symbol.clone(),
            return_values: c1_vals,
            should_track_calls: parent_a[i].should_track_calls,
            default_behavior: parent_a[i].default_behavior.clone(),
        });
        child2.push(MockConfig {
            symbol: mp.symbol.clone(),
            return_values: c2_vals,
            should_track_calls: parent_b[i].should_track_calls,
            default_behavior: parent_b[i].default_behavior.clone(),
        });
    }

    (child1, child2)
}

/// Generate return values for a single mock parameter.
///
/// For declared error types (Result complex kind, or union containing an Error
/// variant), generates both success and error values. For Unknown return types,
/// uses category-aware shaping as a fallback.
fn generate_mock_return_values(
    mp: &MockParam,
    count: usize,
    rng: &mut impl Rng,
    caps: Option<&FrontendCapabilities>,
) -> Vec<Value> {
    // Check for error-producing types first: Result complex kind or union-with-Error
    if let Some(values) = generate_error_aware_values(&mp.return_type, count, rng, caps) {
        return values;
    }

    // For Unknown types, use category-aware fallback
    if mp.return_type == TypeInfo::Unknown {
        return generate_category_shaped_values(mp.category, count, rng);
    }

    // Default: type-driven generation
    (0..count)
        .map(|_| generate_random_value(&mp.return_type, rng, caps))
        .collect()
}

/// Generate values for error-producing types: `Complex { kind: Result }` or
/// union types containing a `Complex { kind: Error }` variant.
///
/// Returns `None` if the type doesn't match these patterns. When matched,
/// produces a mix of success values and error values to exercise both paths.
fn generate_error_aware_values(
    typ: &TypeInfo,
    count: usize,
    rng: &mut impl Rng,
    caps: Option<&FrontendCapabilities>,
) -> Option<Vec<Value>> {
    match typ {
        // Result complex type: generate ok and err variants
        TypeInfo::Complex {
            kind: ComplexKind::Result,
            ..
        } => {
            let mut values = Vec::with_capacity(count);
            for i in 0..count {
                // Alternate: even indices get ok, odd get err (at least one of each if count >= 2)
                if i % 2 == 0 {
                    values.push(json!({"__complex_type": "result", "ok": true, "value": generate_random_value(&TypeInfo::Unknown, rng, caps)}));
                } else {
                    values.push(json!({"__complex_type": "result", "ok": false, "value": "mock error"}));
                }
            }
            Some(values)
        }
        // Union with an Error variant: split between non-error and error values
        TypeInfo::Union { variants } => {
            let error_variants: Vec<&TypeInfo> = variants
                .iter()
                .filter(|v| is_error_type(v))
                .collect();
            let success_variants: Vec<&TypeInfo> = variants
                .iter()
                .filter(|v| !is_error_type(v))
                .collect();

            if error_variants.is_empty() || success_variants.is_empty() {
                return None;
            }

            let mut values = Vec::with_capacity(count);
            for i in 0..count {
                if i % 2 == 0 {
                    let variant =
                        success_variants[rng.random_range(0..success_variants.len())];
                    values.push(generate_random_value(variant, rng, caps));
                } else {
                    let variant =
                        error_variants[rng.random_range(0..error_variants.len())];
                    values.push(generate_random_value(variant, rng, caps));
                }
            }
            Some(values)
        }
        _ => None,
    }
}

/// Check whether a TypeInfo represents an error type.
fn is_error_type(typ: &TypeInfo) -> bool {
    matches!(
        typ,
        TypeInfo::Complex {
            kind: ComplexKind::Error,
            ..
        }
    )
}

/// Generate category-aware default values for Unknown return types.
///
/// Falls back to random generation for categories without meaningful defaults.
fn generate_category_shaped_values(
    category: IoCategory,
    count: usize,
    rng: &mut impl Rng,
) -> Vec<Value> {
    (0..count)
        .map(|_| match category {
            IoCategory::FileSystem => {
                let choice: u8 = rng.random_range(0..4);
                match choice {
                    0 => json!("file content stub"),
                    1 => json!(true),
                    2 => json!([]),
                    _ => Value::Null,
                }
            }
            IoCategory::Network => {
                let choice: u8 = rng.random_range(0..3);
                match choice {
                    0 => json!({"status": 200, "data": {}}),
                    1 => json!({"status": 404, "data": null}),
                    _ => json!({"status": 500, "data": null}),
                }
            }
            IoCategory::Database => {
                let choice: u8 = rng.random_range(0..3);
                match choice {
                    0 => json!({"rows": []}),
                    1 => json!({"rows": [{"id": 1}]}),
                    _ => json!({"rowCount": 1}),
                }
            }
            IoCategory::PureUtility | IoCategory::ExternalOther => {
                generate_unknown(rng)
            }
        })
        .collect()
}

