use crate::auto_mock::{IoCategory, MockParam, ValueSource};
use crate::behavior::{Behavior, BehaviorMap};
use crate::protocol::{SetupContextEntry, SetupContextStack, SetupLevel};

// ---------------------------------------------------------------------------
// Auto-mock strategies
// ---------------------------------------------------------------------------

pub fn arb_io_category() -> impl Strategy<Value = IoCategory> {
    prop_oneof![
        Just(IoCategory::FileSystem),
        Just(IoCategory::Network),
        Just(IoCategory::Database),
        Just(IoCategory::PureUtility),
        Just(IoCategory::ExternalOther),
    ]
}

pub fn arb_value_source() -> impl Strategy<Value = ValueSource> {
    prop_oneof![
        Just(ValueSource::AutoGenerated),
        Just(ValueSource::UserOverride),
        Just(ValueSource::BehaviorMap),
    ]
}

pub fn arb_mock_param() -> impl Strategy<Value = MockParam> {
    (
        arb_ident(),
        arb_type_info(2),
        arb_io_category(),
        1..10u32,
        arb_value_source(),
    )
        .prop_map(|(symbol, return_type, category, call_count_estimate, value_source)| {
            MockParam {
                symbol,
                return_type,
                category,
                call_count_estimate,
                value_source,
            }
        })
}

// ---------------------------------------------------------------------------
// Triage strategies
// ---------------------------------------------------------------------------

// -----------------------------------------------------------------
// generate_mock_values: produces correct count and type-valid values
// -----------------------------------------------------------------

#[test]
fn generate_mock_values_correct_count(
    params in prop::collection::vec(arb_mock_param(), 1..=4),
    seed in 0..10000u64,
) {
    let mut rng = StdRng::seed_from_u64(seed);
    let configs = generate_mock_values(&params, &mut rng, None);
    prop_assert_eq!(configs.len(), params.len(),
        "config count should match param count");

    for (cfg, mp) in configs.iter().zip(params.iter()) {
        prop_assert_eq!(&cfg.symbol, &mp.symbol);
        let expected_count = (mp.call_count_estimate as usize).max(1);
        prop_assert_eq!(cfg.return_values.len(), expected_count,
            "return value count for {} should be {}", mp.symbol, expected_count);
    }
}

// -----------------------------------------------------------------
// generate_mock_values: return values match type for typed params
// -----------------------------------------------------------------

#[test]
fn generate_mock_values_type_valid(
    seed in 0..10000u64,
    typ in prop_oneof![
        Just(TypeInfo::Int),
        Just(TypeInfo::Float),
        Just(TypeInfo::Bool),
        Just(TypeInfo::Str),
    ],
    call_count in 1..5u32,
) {
    let mp = MockParam {
        symbol: "test_fn".to_string(),
        return_type: typ.clone(),
        category: IoCategory::ExternalOther,
        call_count_estimate: call_count,
        value_source: crate::auto_mock::ValueSource::AutoGenerated,
    };
    let mut rng = StdRng::seed_from_u64(seed);
    let configs = generate_mock_values(&[mp], &mut rng, None);
    prop_assert_eq!(configs.len(), 1);
    for val in &configs[0].return_values {
        prop_assert!(
            value_matches_type(val, &typ),
            "value {val:?} doesn't match type {typ:?}"
        );
    }
}

// -----------------------------------------------------------------
// mutate_mock_values: preserves vector structure and type contracts
// -----------------------------------------------------------------

#[test]
fn mutate_mock_values_preserves_structure(
    params in prop::collection::vec(arb_mock_param(), 1..=4),
    seed in 0..10000u64,
) {
    let mut rng = StdRng::seed_from_u64(seed);
    let configs = generate_mock_values(&params, &mut rng, None);
    let mut rng2 = StdRng::seed_from_u64(seed.wrapping_add(1));
    let mutated = mutate_mock_values(&configs, &params, 1.0, &mut rng2);

    prop_assert_eq!(mutated.len(), configs.len(),
        "mutated config count mismatch");
    for (mc, orig) in mutated.iter().zip(configs.iter()) {
        prop_assert_eq!(mc.return_values.len(), orig.return_values.len(),
            "return value count changed after mutation");
        prop_assert_eq!(&mc.symbol, &orig.symbol,
            "symbol changed after mutation");
    }
}

// -----------------------------------------------------------------
// crossover_mock_values: preserves vector structure
// -----------------------------------------------------------------

#[test]
fn crossover_mock_values_preserves_structure(
    params in prop::collection::vec(arb_mock_param(), 1..=4),
    seed in 0..10000u64,
) {
    let mut rng = StdRng::seed_from_u64(seed);
    let parent_a = generate_mock_values(&params, &mut rng, None);
    let mut rng2 = StdRng::seed_from_u64(seed.wrapping_add(1));
    let parent_b = generate_mock_values(&params, &mut rng2, None);

    let mut rng3 = StdRng::seed_from_u64(seed.wrapping_add(2));
    let (child1, child2) = crossover_mock_values(
        &parent_a, &parent_b, &params, 1.0, &mut rng3,
    );

    let expected_len = parent_a.len().min(parent_b.len()).min(params.len());
    prop_assert_eq!(child1.len(), expected_len, "child1 length mismatch");
    prop_assert_eq!(child2.len(), expected_len, "child2 length mismatch");

    for i in 0..expected_len {
        let min_vals = parent_a[i].return_values.len()
            .min(parent_b[i].return_values.len());
        prop_assert_eq!(child1[i].return_values.len(), min_vals,
            "child1 return_values length mismatch at {i}");
        prop_assert_eq!(child2[i].return_values.len(), min_vals,
            "child2 return_values length mismatch at {i}");
    }
}

