                let parent_b = generate_mock_values(&params, &mut rng2, None);

                let mut rng3 = StdRng::seed_from_u64(seed.wrapping_add(2));
                let (child1, child2) = crossover_mock_values(
                    &parent_a, &parent_b, &params, 1.0, &mut rng3,
                );

